import { createRxDatabase, addRxPlugin, type RxStorage } from "rxdb";
import { RxDBMigrationSchemaPlugin } from "rxdb/plugins/migration-schema";
import { RxDBUpdatePlugin } from "rxdb/plugins/update";
import { RxDBQueryBuilderPlugin } from "rxdb/plugins/query-builder";
import { segmentText } from "./segmenter.js";
import { CHARS_PER_SECOND } from "./constants.js";

// Use window/global to track plugin registration across HMR/reloads
declare global {
  var __rxdb_plugins_added: boolean | undefined;
  var __rxdb_devmode_added: boolean | undefined;
}

const _global = typeof window !== "undefined" ? window : globalThis;

// Add essential plugins - only once
if (!_global.__rxdb_plugins_added) {
  try {
    addRxPlugin(RxDBMigrationSchemaPlugin);
    addRxPlugin(RxDBUpdatePlugin);
    addRxPlugin(RxDBQueryBuilderPlugin);
    _global.__rxdb_plugins_added = true;
  } catch (e) {
    console.warn("Plugins might already be added", e);
  }
}

export const documentSchema = {
  version: 8,
  primaryKey: "documentId",
  type: "object",
  properties: {
    documentId: { type: "string", maxLength: 100 },
    segments: { type: "array", items: { type: "string" } },
    fullText: { type: "string" },
    videoLengthAtSegmentation: { type: "number" },
    currentSegmentIndex: { type: "number" },
    currentSegmentProgress: { type: "number" },
    createdAt: { type: "number", multipleOf: 1, minimum: 0, maximum: 100000000000000, maxLength: 100 },
    lastViewedAt: { type: "number", multipleOf: 1, minimum: 0, maximum: 100000000000000, maxLength: 100 },
    isFavourite: { type: "boolean" },
    totalSegments: { type: "number" },
    currentSegmentLength: { type: "number" },
  },
  required: [
    "documentId",
    "segments",
    "createdAt",
    "lastViewedAt",
    "isFavourite",
  ],
} as const;

export const settingsSchema: any = {
  version: 0,
  primaryKey: "id",
  type: "object",
  properties: {
    id: { type: "string", maxLength: 100 },
    playbackSpeed: { type: "number" },
    autoScroll: { type: "boolean" },
    karaokeMode: { type: "boolean" },
    videoLength: { type: "number" },
    isMuted: { type: "boolean" },
  },
  required: [
    "id",
    "playbackSpeed",
    "autoScroll",
    "karaokeMode",
    "videoLength",
    "isMuted",
  ],
} as const;

export const DEFAULT_SETTINGS = {
  id: "global",
  playbackSpeed: 1,
  autoScroll: true,
  karaokeMode: true,
  videoLength: 15,
  isMuted: false,
};

let currentStorage: RxStorage<any, any> | null = null;
let isDev: boolean = false;
let dbPromise: Promise<any> | null = null;

export function setDbStorage(storage: RxStorage<any, any>, devMode: boolean = false) {
  currentStorage = storage;
  isDev = devMode;
}

export function getDb() {
  // Add another layer of check to support the vitest tests bypassing db creation
  if (typeof globalThis !== "undefined" && (globalThis as any).__mockDb) {
    return Promise.resolve((globalThis as any).__mockDb);
  }
  
  if (!currentStorage) {
    return Promise.reject(new Error("Storage adapter not set. Call setDbStorage first."));
  }
  if (!dbPromise) {
    dbPromise = _createDb();
  }
  return dbPromise;
}

async function _createDb() {
  let storage: RxStorage<any, any> = currentStorage!;

  if (isDev) {
    if (!_global.__rxdb_devmode_added) {
      try {
        const { RxDBDevModePlugin } = await import("rxdb/plugins/dev-mode");
        addRxPlugin(RxDBDevModePlugin);
        _global.__rxdb_devmode_added = true;
      } catch (e: unknown) {
        const err = e as { code?: string; message?: string; name?: string };
        const isDev1 =
          err?.code === "DEV1" ||
          String(e).includes("DEV1") ||
          err?.message?.includes?.("DEV1") ||
          err?.name?.includes?.("DEV1");

        if (isDev1) {
          _global.__rxdb_devmode_added = true;
        } else {
          console.warn("Failed to load RxDB Dev Mode Plugin", e);
        }
      }
    }

    try {
      const { wrappedValidateAjvStorage } = await import("rxdb/plugins/validate-ajv");
      storage = wrappedValidateAjvStorage({ storage });
    } catch (e) {
      console.warn("Failed to load RxDB AJV Validation Storage Wrapper", e);
    }
  }

  try {
    const db = await createRxDatabase({
      name: "paperflipdb_" + Math.random().toString(36).substring(7) + "_" + Date.now(),
      storage,
      ignoreDuplicate: true,
    });

    await db.addCollections({
      documents: {
        schema: documentSchema,
        migrationStrategies: {
          1: (oldDoc: any) => { oldDoc.createdAt = oldDoc.createdAt || Date.now(); oldDoc.lastViewedAt = oldDoc.lastViewedAt || oldDoc.createdAt; oldDoc.isFavourite = oldDoc.isFavourite || false; return oldDoc; },
          2: (oldDoc: any) => { oldDoc.createdAt = oldDoc.createdAt || Date.now(); oldDoc.lastViewedAt = oldDoc.lastViewedAt || oldDoc.createdAt; return oldDoc; },
          3: (oldDoc: any) => { oldDoc.createdAt = oldDoc.createdAt || Date.now(); oldDoc.lastViewedAt = oldDoc.lastViewedAt || oldDoc.createdAt; return oldDoc; },
          4: (oldDoc: any) => { oldDoc.createdAt = oldDoc.createdAt || Date.now(); oldDoc.lastViewedAt = oldDoc.lastViewedAt || oldDoc.createdAt; return oldDoc; },
          5: (oldDoc: any) => { oldDoc.createdAt = oldDoc.createdAt || Date.now(); oldDoc.lastViewedAt = oldDoc.lastViewedAt || oldDoc.createdAt; return oldDoc; },
          6: (oldDoc: any) => { oldDoc.createdAt = oldDoc.createdAt || Date.now(); oldDoc.lastViewedAt = oldDoc.lastViewedAt || oldDoc.createdAt; return oldDoc; },
          7: (oldDoc: any) => {
            oldDoc.fullText = oldDoc.fullText || oldDoc.segments.join("\n\n");
            oldDoc.videoLengthAtSegmentation = oldDoc.videoLengthAtSegmentation || 15;
            return oldDoc;
          },
          8: (oldDoc: any) => {
            oldDoc.totalSegments = oldDoc.segments?.length || 0;
            oldDoc.currentSegmentLength = oldDoc.segments && oldDoc.currentSegmentIndex !== undefined && oldDoc.segments[oldDoc.currentSegmentIndex]
              ? oldDoc.segments[oldDoc.currentSegmentIndex].length
              : 0;
            return oldDoc;
          },
        },
      },
      settings: {
        schema: settingsSchema,
      },
    });

    const settingsDoc = await db.settings.findOne("global").exec();
    if (!settingsDoc) {
      await db.settings.insert(DEFAULT_SETTINGS);
    }

    return db;
  } catch (error) {
    console.error("Failed to initialize RxDB:", error);
    throw error;
  }
}

export async function addDocument(documentId: string, segments: string[], fullText: string = "", videoLengthAtSegmentation: number = 15, currentSegmentIndex: number = 0) {
  try {
    const db = await getDb();
    const now = Date.now();
    const currentSegmentLength = segments[currentSegmentIndex]?.length || 0;
    const doc = await db.documents.insert({
      documentId,
      segments,
      fullText,
      videoLengthAtSegmentation,
      currentSegmentIndex,
      currentSegmentProgress: 0,
      createdAt: now,
      lastViewedAt: now,
      isFavourite: false,
      totalSegments: segments.length,
      currentSegmentLength,
    });
    return doc.toJSON();
  } catch (error) {
    console.error(`Failed to add document ${documentId}:`, error);
    throw error;
  }
}

export async function upsertDocument(documentId: string, segments: string[], fullText: string = "", videoLengthAtSegmentation: number = 15, currentSegmentIndex: number = 0) {
  try {
    const db = await getDb();
    const now = Date.now();
    const currentSegmentLength = segments[currentSegmentIndex]?.length || 0;
    const doc = await db.documents.upsert({
      documentId,
      segments,
      fullText,
      videoLengthAtSegmentation,
      currentSegmentIndex,
      currentSegmentProgress: 0,
      createdAt: now,
      lastViewedAt: now,
      isFavourite: false,
      totalSegments: segments.length,
      currentSegmentLength,
    });
    return doc.toJSON();
  } catch (error) {
    console.error(`Failed to upsert document ${documentId}:`, error);
    throw error;
  }
}

export async function getRecentUploads(limit: number = 10) {
  const db = await getDb();
  const docs = await db.documents.find().sort({ lastViewedAt: "desc" }).limit(limit).exec();
  return docs.map((doc: any) => {
    const json = doc.toJSON();
    delete json.segments;
    return json;
  });
}

export async function getDocument(documentId: string) {
  const db = await getDb();
  const doc = await db.documents.findOne(documentId).exec();
  if (doc) {
    await doc.incrementalPatch({ lastViewedAt: Date.now() });
    return doc.toJSON();
  }
  return null;
}

export async function updateDocumentProgress(documentId: string, index: number, progress: number = 0) {
  try {
    const db = await getDb();
    const doc = await db.documents.findOne(documentId).exec();
    if (doc) {
      const segments = doc.segments || [];
      const currentSegmentLength = segments[index]?.length || 0;
      await doc.incrementalPatch({
        currentSegmentIndex: index,
        currentSegmentProgress: progress,
        currentSegmentLength,
        lastViewedAt: Date.now(),
      });
    }
  } catch (error) {
    console.error(`Failed to update progress for ${documentId}:`, error);
  }
}

export async function toggleFavourite(documentId: string) {
  try {
    const db = await getDb();
    const doc = await db.documents.findOne(documentId).exec();
    if (doc) {
      const newStatus = !doc.isFavourite;
      await doc.incrementalPatch({ isFavourite: newStatus });
      return newStatus;
    }
  } catch (error) {
    console.error(`Failed to toggle favourite for ${documentId}:`, error);
  }
  return false;
}

export async function deleteDocument(documentId: string) {
  try {
    const db = await getDb();
    const doc = await db.documents.findOne(documentId).exec();
    if (doc) {
      await doc.remove();
      return true;
    }
  } catch (error) {
    console.error(`Failed to delete document ${documentId}:`, error);
  }
  return false;
}

export function resetDb() {
  dbPromise = null;
}

export async function getAllDocuments() {
  const db = await getDb();
  const docs = await db.documents.find().sort({ lastViewedAt: "desc" }).exec();
  return docs.map((doc: any) => {
    const json = doc.toJSON();
    delete json.segments;
    return json;
  });
}

export type Settings = typeof DEFAULT_SETTINGS;
export async function getSettings() {
  const db = await getDb();
  const doc = await db.settings.findOne("global").exec();
  return doc ? doc.toJSON() : DEFAULT_SETTINGS;
}

export async function updateSettings(patch: Partial<typeof DEFAULT_SETTINGS>) {
  try {
    const db = await getDb();
    const doc = await db.settings.findOne("global").exec();
    if (doc) {
      await doc.incrementalPatch(patch);
    } else {
      await db.settings.insert({ ...DEFAULT_SETTINGS, ...patch });
    }
  } catch (error) {
    console.error("Failed to update settings:", error);
  }
}

export async function getSettingsObservable() {
  const db = await getDb();
  return db.settings.findOne("global").$;
}

export async function resegmentDocument(documentId: string, newVideoLength: number) {
  try {
    const db = await getDb();
    const doc = await db.documents.findOne(documentId).exec();
    if (!doc || !doc.fullText) return null;

    const oldSegments = doc.segments || [];
    const oldIndex = doc.currentSegmentIndex || 0;
    const oldProgress = doc.currentSegmentProgress || 0;

    let globalOffset = oldProgress;
    const len = Math.min(oldIndex, oldSegments.length);
    for (let i = 0; i < len; i++) {
      globalOffset += oldSegments[i].length;
    }

    const maxChars = Math.max(1, Math.round(newVideoLength * CHARS_PER_SECOND));
    const newSegments = segmentText(doc.fullText, maxChars);

    let newIndex = 0;
    let accumulatedLength = 0;
    let newProgress = 0;

    for (let i = 0; i < newSegments.length; i++) {
      const segmentLength = newSegments[i].length;
      if (accumulatedLength + segmentLength > globalOffset) {
        newIndex = i;
        newProgress = globalOffset - accumulatedLength;
        break;
      }
      accumulatedLength += segmentLength;
      if (i === newSegments.length - 1) {
        newIndex = i;
        newProgress = segmentLength;
      }
    }

    const currentSegmentLength = newSegments[newIndex]?.length || 0;

    await doc.incrementalPatch({
      segments: newSegments,
      videoLengthAtSegmentation: newVideoLength,
      currentSegmentIndex: newIndex,
      currentSegmentProgress: newProgress,
      totalSegments: newSegments.length,
      currentSegmentLength,
    });

    return doc.toJSON();
  } catch (error) {
    console.error(`Failed to resegment document ${documentId}:`, error);
    throw error;
  }
}
